SELECT COUNT(*) AS failed_compilations
FROM compilation_status
WHERE error_count > 0;

SELECT status_message, compiler_version
FROM compilation_status
WHERE error_count > 1;

SELECT include_path, framework_include_path, created_at
FROM include_paths
WHERE created_by = 1;

SELECT config_id, COUNT(path_id) AS path_count
FROM include_paths
GROUP BY config_id;

SELECT config_id, SUM(error_count) AS total_errors, SUM(warning_count) AS total_warnings
FROM compilation_status
GROUP BY config_id;

SELECT DISTINCT u.role
FROM configurations c
JOIN users u ON c.created_by = u.user_id;
